use std::collections::HashMap;

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let mut graph: HashMap<usize, Vec<(usize, i64)>> = HashMap::new();
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        graph.entry(u).or_insert_with(Vec::new).push((v, w));
        graph.entry(v).or_insert_with(Vec::new).push((u, w));
    }

    let mut parent: Vec<usize> = (0..n).collect();
    let mut rank: Vec<usize> = vec![1; n];

    fn find(parent: &mut Vec<usize>, u: usize) -> usize {
        while parent[u] != u {
            parent[u] = parent[parent[u]];
            u = parent[u];
        }
        u
    }

    fn union(parent: &mut Vec<usize>, rank: &mut Vec<usize>, u: usize, v: usize) -> bool {
        let u_root = find(parent, u);
        let v_root = find(parent, v);
        if u_root == v_root {
            return false;
        }
        if rank[u_root] < rank[v_root] {
            parent[u_root] = v_root;
            rank[v_root] += rank[u_root];
        } else {
            parent[v_root] = u_root;
            rank[u_root] += rank[v_root];
        }
        true
    }

    let mut edges: Vec<_> = graph.iter().flat_map(|(&u, &(v, w))| {
        vec![(u, v, w)]
    }).collect();
    edges.sort_by(|a, b| a.2.cmp(&b.2));

    let mut components = n;
    let mut max_edge = 0;

    for (u, v, w) in edges {
        if components > k {
            return max_edge;
        }
        if find(&mut parent, u) != find(&mut parent, v) {
            union(&mut parent, &mut rank, u, v);
            components -= 1;
            max_edge = max_edge.max(w);
        }
    }

    max_edge
}
